import anthropic

client = anthropic.Anthropic()

PROBLEM = "Design a caching strategy for a high-traffic web API."

CANDIDATES = [
    "Use an in-memory cache (Redis) with a TTL of 60 seconds for all GET endpoints.",
    "Cache at the CDN layer only; rely on HTTP Cache-Control headers.",
    "No cache — serve every request from the database and rely on database read replicas.",
    "Use a two-layer cache: CDN for static assets, Redis for dynamic data with per-route TTLs.",
]


# --- Approach 1: Individual numeric scores (independent calls) ---

def score_individual(problem: str, thought: str) -> float:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=10,
        temperature=0.0,
        messages=[{
            "role": "user",
            "content": (
                f"Problem: {problem}\n"
                f"Proposed step: {thought}\n"
                "Rate 0–10 for how well this addresses the problem. Reply with only the number."
            ),
        }],
    ).content[0].text.strip()
    try:
        return float(resp.split()[0])
    except (ValueError, IndexError):
        return 5.0


print("Individual scores:")
for c in CANDIDATES:
    s = score_individual(PROBLEM, c)
    print(f"  {s:.1f}  {c[:70]}")


# --- Approach 2: Comparative ranking (one call, all candidates together) ---

def rank_comparatively(problem: str, candidates: list[str]) -> list[int]:
    """Return indices of candidates sorted best-to-worst."""
    numbered = "\n".join(f"{i+1}. {c}" for i, c in enumerate(candidates))
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=50,
        temperature=0.0,
        messages=[{
            "role": "user",
            "content": (
                f"Problem: {problem}\n\n"
                f"Rank these options best to worst for solving the problem:\n{numbered}\n\n"
                "Reply with ONLY the option numbers in order, comma-separated (e.g. 4,2,1,3)."
            ),
        }],
    ).content[0].text.strip()
    try:
        import re
        nums = [int(x.strip()) - 1 for x in re.findall(r"\d+", resp)]
        return [n for n in nums if 0 <= n < len(candidates)]
    except Exception:
        return list(range(len(candidates)))


ranking = rank_comparatively(PROBLEM, CANDIDATES)
print("\nComparative ranking (best first):")
for rank, idx in enumerate(ranking, 1):
    print(f"  {rank}. {CANDIDATES[idx][:70]}")

# Always add a call budget
MAX_CALLS = 30
call_count = 0

def generate_with_budget(*args, **kwargs):
    global call_count
    call_count += 1
    if call_count > MAX_CALLS:
        raise RuntimeError(f"ToT search exceeded budget of {MAX_CALLS} calls")
    return client.messages.create(*args, **kwargs)
